starter.javascript:
let isVIP = false;
let hasFastPass = true;
let rideClosed = false;
// work inside-out: OR is inclusive, NOT flips its operand
// print the Boolean value of the whole expression

reference.javascript:
let isVIP = false;
let hasFastPass = true;
let rideClosed = false;
let expressLane = (isVIP || hasFastPass) && (!rideClosed);
console.log(expressLane ? "True" : "False");

